import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        List<Long> tokens = new ArrayList<>();
        String line;
        while ((line = br.readLine()) != null) {
            line = line.trim();
            if (line.isEmpty()) continue;
            tokens.add(Long.parseLong(line));
        }
        if (tokens.isEmpty()) return;
        int idx = 0;
        int T = tokens.get(idx++).intValue();
        StringBuilder out = new StringBuilder();
        for (int t = 0; t < T; t++) {
            if (idx >= tokens.size()) {
                // Incomplete test case, produce no output
                System.out.print("");
                return;
            }
            int N = tokens.get(idx++).intValue();
            if (idx + N > tokens.size()) {
                // Not enough numbers for this test case
                System.out.print("");
                return;
            }
            long sum = 0L;
            long prod = 1L;
            for (int i = 0; i < N; i++) {
                long x = tokens.get(idx++);
                sum += x;
                prod *= x;
            }
            out.append(sum).append(' ').append(prod);
            if (t != T - 1) out.append('\n');
        }
        System.out.print(out.toString());
    }
}

